static int fd=-1,running=1;
static cl_context ctx;static cl_device_id dev;static cl_command_queue q;
static cl_program pr;static cl_kernel kr;
static cl_mem dB,dV,dS;
static uint64_t thashes=0,tacc=0,trej=0;
